import{_ as a,C as n,o as r,c as o,j as s,a as i,E as h,a4 as l}from"./chunks/framework.DeS7hvj6.js";const F=JSON.parse('{"title":"Token Search","description":"Split multi-word queries into terms, fuzzy-match each with the Bitap algorithm, and rank results using BM25-style IDF weighting. Handles typos per word independently.","frontmatter":{"title":"Token Search","description":"Split multi-word queries into terms, fuzzy-match each with the Bitap algorithm, and rank results using BM25-style IDF weighting. Handles typos per word independently."},"headers":[],"relativePath":"token-search.md","filePath":"token-search.md"}'),d={name:"token-search.md"},p={id:"token-search",tabindex:"-1"};function c(k,e,u,E,g,y){const t=n("Badge");return r(),o("div",null,[s("h1",p,[e[0]||(e[0]=i("Token Search ",-1)),h(t,{type:"tip",text:"New"}),e[1]||(e[1]=i()),e[2]||(e[2]=s("a",{class:"header-anchor",href:"#token-search","aria-label":'Permalink to "Token Search <Badge type="tip" text="New" />"'},"​",-1))]),e[3]||(e[3]=l(`<p>Token search splits multi-word queries into individual terms, fuzzy-matches each term independently using the Bitap algorithm, and ranks results using BM25-style IDF weighting.</p><h2 id="when-to-use-it" tabindex="-1">When to Use It <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to Use It&quot;">​</a></h2><p>The default fuzzy search treats the entire query as a single pattern. That works well for short, single-word lookups like <code>&quot;javscript&quot;</code> → <code>&quot;JavaScript&quot;</code>. But for multi-word queries like <code>&quot;javascript design patterns&quot;</code>, a single Bitap search hits the 32-character limit and can&#39;t match each word independently.</p><p>Token search is designed for these cases:</p><ul><li><strong>Search bars</strong> — users type natural multi-word queries like <code>&quot;react state management&quot;</code></li><li><strong>Document search</strong> — matching across titles, descriptions, or body text where multiple terms matter</li><li><strong>Autocomplete</strong> — ranking results by how many query terms they match, with rare terms weighted higher</li></ul><p>If your queries are typically one word or a short phrase, the default fuzzy search is simpler and faster.</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#F97583;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#79B8FF;--shiki-dark:#79B8FF;"> fuse</span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;"> Fuse</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">(docs, {</span></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">  useTokenSearch: </span><span style="--shiki-light:#79B8FF;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">  keys: [</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;title&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;author&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;description&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">fuse.</span><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;">search</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;javascrpt paterns&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// → [{ item: { title: &#39;JavaScript Patterns&#39;, ... }, score: 0.12 }]</span></span></code></pre></div><p>All standard options work as before: <code>includeScore</code>, <code>includeMatches</code>, <code>keys</code> with weights, <code>threshold</code>, <code>limit</code>, <code>shouldSort</code>, etc.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><p><strong>Tokenization</strong> — The query is split into individual words using word boundary matching (<code>\\b\\w+\\b</code>). Each word becomes a separate fuzzy search.</p></li><li><p><strong>Per-term fuzzy matching</strong> — Each term is matched against each field using the Bitap algorithm with <code>ignoreLocation: true</code>, so terms can appear anywhere in the field. This means multi-word queries are no longer limited by the 32-character Bitap pattern cap.</p></li><li><p><strong>IDF weighting</strong> — An inverted index is built at construction time. The IDF weight for each term uses the BM25 formula:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span>idf = log(1 + (fieldCount - docFreq + 0.5) / (docFreq + 0.5))</span></span></code></pre></div><p>Rare terms (appearing in fewer documents) are weighted higher than common terms. A match on a distinctive word contributes more to the score than a match on a ubiquitous one.</p></li><li><p><strong>Score combination</strong> — Per-term scores are combined additively with IDF weights, then normalized to Fuse&#39;s 0–1 range (0 = perfect match).</p></li></ol><h2 id="key-behaviors" tabindex="-1">Key Behaviors <a class="header-anchor" href="#key-behaviors" aria-label="Permalink to &quot;Key Behaviors&quot;">​</a></h2><ul><li><strong>Partial matching</strong> — A document matching 2 of 3 query terms still returns, but ranks lower than one matching all 3.</li><li><strong>Word order independence</strong> — <code>&quot;patterns javascript&quot;</code> and <code>&quot;javascript patterns&quot;</code> produce identical results.</li><li><strong>Typo tolerance per term</strong> — Each term is fuzzy-matched independently, so typos in any word are tolerated.</li><li><strong>Long queries work</strong> — A 6-word query runs 6 independent Bitap searches, each within the 32-char limit.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use <code>threshold</code> to control fuzziness. The default <code>0.6</code> is permissive — for tighter matching, try <code>0.3</code> or <code>0.4</code>.</li><li>Use <code>limit</code> when you only need the top N results. This also improves performance via heap-based selection.</li><li>Key weights still apply on top of token search scoring, so you can boost title matches over body matches.</li></ul><h2 id="dynamic-collection-updates" tabindex="-1">Dynamic Collection Updates <a class="header-anchor" href="#dynamic-collection-updates" aria-label="Permalink to &quot;Dynamic Collection Updates&quot;">​</a></h2><p>The inverted index is maintained as you modify the collection:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-dark github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#F97583;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#79B8FF;--shiki-dark:#79B8FF;"> fuse</span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;"> Fuse</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">(docs, { useTokenSearch: </span><span style="--shiki-light:#79B8FF;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">, keys: [</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;title&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">] })</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Adding a document updates the inverted index</span></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">fuse.</span><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;">add</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">({ title: </span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;">&#39;New Book&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;"> })</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Removing documents also updates the index</span></span>
<span class="line"><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">fuse.</span><span style="--shiki-light:#B392F0;--shiki-dark:#B392F0;">remove</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#FFAB70;--shiki-dark:#FFAB70;">doc</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;"> doc.title </span><span style="--shiki-light:#F97583;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#9ECBFF;--shiki-dark:#9ECBFF;"> &#39;Old Book&#39;</span><span style="--shiki-light:#E1E4E8;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>Benchmarked on randomly generated documents with 2 keys (title + body):</p><table tabindex="0"><thead><tr><th>Metric</th><th>100 docs</th><th>1,000 docs</th><th>5,000 docs</th></tr></thead><tbody><tr><td>Index creation overhead</td><td>2.5x</td><td>5.2x</td><td>5.5x</td></tr><tr><td>Single-term search</td><td>1.8x</td><td>1.8x</td><td>1.7x</td></tr><tr><td>Multi-term search</td><td>1.3x</td><td>1.3x</td><td>1.2x</td></tr></tbody></table><p>Index creation is a one-time cost (46ms for 5,000 docs). Search overhead is 1.2–1.8x depending on query complexity, primarily because each query term runs its own Bitap search. The inverted index lookup itself is O(1) per term.</p><h2 id="availability" tabindex="-1">Availability <a class="header-anchor" href="#availability" aria-label="Permalink to &quot;Availability&quot;">​</a></h2><p>Token search is available in the <strong>full build</strong> only (<code>fuse.js</code> / <code>fuse.mjs</code>). It is not included in the basic build to keep bundle size small. Using <code>useTokenSearch: true</code> with the basic build throws an error.</p><p>To use token search, use the full build.</p>`,24))])}const b=a(d,[["render",c]]);export{F as __pageData,b as default};
